import java.util.*;
public class BTTemplate {
    static List<List<Integer>> results=new ArrayList<>();
    static void backtrack(List<Integer> current, int start, int[] candidates, int target){
        if(target==0){results.add(new ArrayList<>(current));return;}
        if(target<0)return;
        for(int i=start;i<candidates.length;i++){
            current.add(candidates[i]);
            backtrack(current,i,candidates,target-candidates[i]); // i not i+1 to allow reuse
            current.remove(current.size()-1); // BACKTRACK
        }
    }
    public static void main(String[] a){results=new ArrayList<>();backtrack(new ArrayList<>(),0,new int[]{2,3,6,7},7);System.out.println(results);System.out.println("Template: choose→recurse→undo. O(2^n) to O(n!) depending on branching.");}
}

import java.util.*;
public class Permutations {
    static List<List<Integer>> res=new ArrayList<>();
    static void bt(int[] nums, boolean[] used, List<Integer> curr){
        if(curr.size()==nums.length){res.add(new ArrayList<>(curr));return;}
        for(int i=0;i<nums.length;i++){
            if(used[i])continue;
            used[i]=true;curr.add(nums[i]);
            bt(nums,used,curr);
            curr.remove(curr.size()-1);used[i]=false;} // backtrack
    }
    public static void main(String[] a){res=new ArrayList<>();bt(new int[]{1,2,3},new boolean[3],new ArrayList<>());System.out.println(res.size());System.out.println("6 permutations of [1,2,3]. O(n!). used[] tracks available elements.");}
}

import java.util.*;
public class Combinations {
    static List<List<Integer>> res=new ArrayList<>();
    static void bt(int n,int k,int start,List<Integer> curr){
        if(curr.size()==k){res.add(new ArrayList<>(curr));return;}
        for(int i=start;i<=n;i++){curr.add(i);bt(n,k,i+1,curr);curr.remove(curr.size()-1);}}
    public static void main(String[] a){res=new ArrayList<>();bt(4,2,1,new ArrayList<>());System.out.println(res.size());System.out.println("6 combinations of C(4,2). Start from i+1 to avoid repeats. O(C(n,k)).");}
}

import java.util.*;
public class Subsets {
    static List<List<Integer>> res=new ArrayList<>();
    static void bt(int[] nums, int start, List<Integer> curr){
        res.add(new ArrayList<>(curr)); // add at every call (not just leaf)
        for(int i=start;i<nums.length;i++){curr.add(nums[i]);bt(nums,i+1,curr);curr.remove(curr.size()-1);}
    }
    public static void main(String[] a){res=new ArrayList<>();bt(new int[]{1,2,3},0,new ArrayList<>());System.out.println(res.size());System.out.println("8 subsets (2^3). Add current at every call. O(2^n).");}
}

import java.util.*;
public class CombSum {
    static List<List<Integer>> res=new ArrayList<>();
    static void bt(int[] c,int t,int start,List<Integer> curr){if(t==0){res.add(new ArrayList<>(curr));return;}for(int i=start;i<c.length;i++){if(c[i]>t)break;curr.add(c[i]);bt(c,t-c[i],i,curr);curr.remove(curr.size()-1);}}
    public static void main(String[] a){res=new ArrayList<>();int[] c={2,3,6,7};java.util.Arrays.sort(c);bt(c,7,0,new ArrayList<>());System.out.println(res);System.out.println("[[2,2,3],[7]] — i not i+1 allows reuse. Sort+prune: if c[i]>target break.");}
}

import java.util.*;
public class PhoneLetters {
    static final String[] MAP={"","","abc","def","ghi","jkl","mno","pqrs","tuv","wxyz"};
    static List<String> res=new ArrayList<>();
    static void bt(String digits,int i,StringBuilder curr){if(i==digits.length()){res.add(curr.toString());return;}for(char c:MAP[digits.charAt(i)-'0'].toCharArray()){curr.append(c);bt(digits,i+1,curr);curr.deleteCharAt(curr.length()-1);}}
    public static void main(String[] a){res=new ArrayList<>();bt("23",0,new StringBuilder());System.out.println(res.size());System.out.println(res.get(0));System.out.println("9 combinations for '23'. StringBuilder: deleteCharAt(len-1) to backtrack.");}
}

import java.util.*;
public class NQueens {
    static List<List<String>> res=new ArrayList<>();
    static void bt(int n,int row,int[] queens){
        if(row==n){List<String> sol=new ArrayList<>();for(int r=0;r<n;r++){char[] line=new char[n];java.util.Arrays.fill(line,'.');line[queens[r]]='Q';sol.add(new String(line));}res.add(sol);return;}
        for(int col=0;col<n;col++){boolean ok=true;for(int r=0;r<row;r++)if(queens[r]==col||Math.abs(queens[r]-col)==Math.abs(r-row)){ok=false;break;}if(ok){queens[row]=col;bt(n,row+1,queens);}}}
    public static void main(String[] a){res=new ArrayList<>();bt(4,0,new int[4]);System.out.println(res.size());System.out.println("2 solutions for N=4. Conflict check: same column or diagonal |r1-r2|==|c1-c2|.");}
}

public class WordSearch {
    static boolean search(char[][] b,String word){for(int r=0;r<b.length;r++)for(int c=0;c<b[0].length;c++)if(dfs(b,word,r,c,0))return true;return false;}
    static boolean dfs(char[][] b,String w,int r,int c,int i){if(i==w.length())return true;if(r<0||r>=b.length||c<0||c>=b[0].length||b[r][c]!=w.charAt(i))return false;char tmp=b[r][c];b[r][c]='#';boolean res=dfs(b,w,r+1,c,i+1)||dfs(b,w,r-1,c,i+1)||dfs(b,w,r,c+1,i+1)||dfs(b,w,r,c-1,i+1);b[r][c]=tmp;return res;}
    public static void main(String[] a){char[][] b={{'A','B','C','E'},{'S','F','C','S'},{'A','D','E','E'}};System.out.println(search(b,"ABCCED"));System.out.println(search(b,"SEE"));System.out.println(search(b,"ABCB"));System.out.println("Mark visited with '#'; restore after DFS. O(m*n*4^L).");}
}

import java.util.*;
public class PalinPartition {
    static List<List<String>> res=new ArrayList<>();
    static void bt(String s,int start,List<String> curr){if(start==s.length()){res.add(new ArrayList<>(curr));return;}for(int end=start+1;end<=s.length();end++){String sub=s.substring(start,end);if(isPalin(sub)){curr.add(sub);bt(s,end,curr);curr.remove(curr.size()-1);}}}
    static boolean isPalin(String s){int l=0,r=s.length()-1;while(l<r)if(s.charAt(l++)!=s.charAt(r--))return false;return true;}
    public static void main(String[] a){res=new ArrayList<>();bt("aab",0,new ArrayList<>());System.out.println(res);System.out.println("[[a,a,b],[aa,b]] — try all substrings from start; only recurse if palindrome.");}
}

import java.util.*;
public class BTSynth {
    static List<List<Integer>> perms(int[] nums){List<List<Integer>> res=new ArrayList<>();btp(nums,new boolean[nums.length],new ArrayList<>(),res);return res;}
    static void btp(int[] n,boolean[] u,List<Integer> c,List<List<Integer>> res){if(c.size()==n.length){res.add(new ArrayList<>(c));return;}for(int i=0;i<n.length;i++){if(u[i])continue;u[i]=true;c.add(n[i]);btp(n,u,c,res);c.remove(c.size()-1);u[i]=false;}}
    static List<List<Integer>> subs(int[] nums){List<List<Integer>> res=new ArrayList<>();bts(nums,0,new ArrayList<>(),res);return res;}
    static void bts(int[] n,int s,List<Integer> c,List<List<Integer>> res){res.add(new ArrayList<>(c));for(int i=s;i<n.length;i++){c.add(n[i]);bts(n,i+1,c,res);c.remove(c.size()-1);}}
    public static void main(String[] a){System.out.println(perms(new int[]{1,2,3}).size());System.out.println(subs(new int[]{1,2,3}).size());boolean ok=perms(new int[]{1,2,3}).size()==6&&subs(new int[]{1,2,3}).size()==8;System.out.println("All pass: "+ok);}
}

import java.util.*;
public class M40Final {
    static List<List<Integer>> combinationSum(int[] c,int t){List<List<Integer>> res=new ArrayList<>();java.util.Arrays.sort(c);cbt(c,t,0,new ArrayList<>(),res);return res;}
    static void cbt(int[] c,int t,int s,List<Integer> curr,List<List<Integer>> res){if(t==0){res.add(new ArrayList<>(curr));return;}for(int i=s;i<c.length;i++){if(c[i]>t)break;curr.add(c[i]);cbt(c,t-c[i],i,curr,res);curr.remove(curr.size()-1);}}
    static List<List<Integer>> subsets(int[] n){List<List<Integer>> res=new ArrayList<>();bts(n,0,new ArrayList<>(),res);return res;}
    static void bts(int[] n,int s,List<Integer> c,List<List<Integer>> res){res.add(new ArrayList<>(c));for(int i=s;i<n.length;i++){c.add(n[i]);bts(n,i+1,c,res);c.remove(c.size()-1);}}
    static int nQueens(int n){int[] q=new int[n];int[] cnt={0};nbt(n,0,q,cnt);return cnt[0];}
    static void nbt(int n,int r,int[] q,int[] cnt){if(r==n){cnt[0]++;return;}for(int c=0;c<n;c++){boolean ok=true;for(int i=0;i<r;i++)if(q[i]==c||Math.abs(q[i]-c)==Math.abs(i-r)){ok=false;break;}if(ok){q[r]=c;nbt(n,r+1,q,cnt);}}}
    public static void main(String[] a){System.out.println("combSum="+combinationSum(new int[]{2,3,6,7},7));System.out.println("subsets="+subsets(new int[]{1,2,3}).size());System.out.println("nQueens4="+nQueens(4));boolean ok=combinationSum(new int[]{2,3,6,7},7).size()==2&&subsets(new int[]{1,2,3}).size()==8&&nQueens(4)==2;System.out.println("All pass: "+ok);}
}
